#!/usr/bin/env python3
"""
ctrlX Data Layer Provider Template
SDK Version: ctrlx-datalayer >= 2.4
"""
import signal
import sys
import time
import flatbuffers
from ctrlx_datalayer import system as dl_system
from ctrlx_datalayer.provider import Provider
from ctrlx_datalayer.provider_node import ProviderNode, NodeCallback
from ctrlx_datalayer.variant import Variant, VariantType
from ctrlx_datalayer.helper import get_datalayer_system_url

# ── Schema import (generated by flatc) ──────────────────────────────────────
# from {company}.{app}.SensorReading import SensorReading
# from {company}.{app} import SensorReading as SensorReadingFbs

APP_NAME = "ctrlx-{company}-{app}"
NODE_BASE = "{company}/{app}"

_provider: Provider = None
_system = None
_running = True


def on_read(node_path: str, output: Variant) -> int:
    """Handle read requests from Data Layer clients."""
    # Build Flatbuffers response
    builder = flatbuffers.Builder(256)
    # TODO: construct your table here, e.g.:
    # from {company}.{app}.SensorReading import SensorReadingStart, SensorReadingAddValue, SensorReadingEnd
    # SensorReadingStart(builder)
    # SensorReadingAddValue(builder, 42.0)
    # reading = SensorReadingEnd(builder)
    # builder.Finish(reading)
    # buf = bytes(builder.Output())
    # output.set_flatbuffers(buf)

    output.set_float64(42.0)  # Replace with actual data
    return 0  # DL_OK


def on_write(node_path: str, input: Variant) -> int:
    """Handle write requests from Data Layer clients."""
    try:
        value = input.get_float64()
        print(f"[{APP_NAME}] Written: {value}")
        return 0  # DL_OK
    except Exception as e:
        print(f"[{APP_NAME}] Write error: {e}", file=sys.stderr)
        return 1  # DL_FAILED


def on_metadata(node_path: str, output: Variant) -> int:
    """Return node metadata (unit, description)."""
    output.set_string('{"unit": "°C", "description": "Sensor value"}')
    return 0


def shutdown(sig, frame):
    global _running
    print(f"[{APP_NAME}] Shutting down...")
    _running = False


def main():
    global _provider, _system

    signal.signal(signal.SIGTERM, shutdown)
    signal.signal(signal.SIGINT, shutdown)

    # Initialize Data Layer system
    _system = dl_system.System("")
    _system.start(False)

    url = get_datalayer_system_url()  # Returns "ipc://" inside snap
    print(f"[{APP_NAME}] Connecting to Data Layer: {url}")

    # Create provider
    _provider = _system.factory().create_provider(url)
    if _provider is None:
        print(f"[{APP_NAME}] Failed to create provider", file=sys.stderr)
        sys.exit(1)

    result = _provider.start()
    if result != 0:
        print(f"[{APP_NAME}] Provider start failed: {result}", file=sys.stderr)
        sys.exit(1)

    # Register nodes
    nodes = [
        f"{NODE_BASE}/sensor/value",
        f"{NODE_BASE}/sensor/status",
    ]
    for path in nodes:
        node = ProviderNode(
            NodeCallback(on_read=on_read, on_write=on_write, on_metadata=on_metadata)
        )
        r = _provider.register_node(path, node)
        if r != 0:
            print(f"[{APP_NAME}] Failed to register {path}: {r}", file=sys.stderr)
        else:
            print(f"[{APP_NAME}] Registered: {path}")

    print(f"[{APP_NAME}] Running. Press Ctrl+C to stop.")

    # Main loop
    while _running:
        time.sleep(1.0)

    # Graceful shutdown
    for path in nodes:
        _provider.unregister_node(path)
    _provider.stop()
    _system.stop()
    print(f"[{APP_NAME}] Stopped.")


if __name__ == "__main__":
    main()
